function isLogicallyChanged<T extends {fileName: string}>(
  sf: T,
  node: FileNode,
  changedTsPaths: ReadonlySet<AbsoluteFsPath>,
  deletedTsPaths: ReadonlySet<AbsoluteFsPath>,
  changedResources: ReadonlySet<AbsoluteFsPath>,
): boolean {
  // A file is assumed to have logically changed if its dependencies could not be determined
  // accurately.
  if (node.failedAnalysis) {
    return true;
  }

  const sfPath = absoluteFromSourceFile(sf);

  // A file is logically changed if it has physically changed itself (including being deleted).
  if (changedTsPaths.has(sfPath) || deletedTsPaths.has(sfPath)) {
    return true;
  }

  // A file is logically changed if one of its dependencies has physically changed.
  for (const dep of node.dependsOn) {
    if (changedTsPaths.has(dep) || deletedTsPaths.has(dep)) {
      return true;
    }
  }

  // A file is logically changed if one of its resources has physically changed.
  for (const dep of node.usesResources) {
    if (changedResources.has(dep)) {
      return true;
    }
  }
  return false;
}

private _appendExcerptTokenWithHyperlinks(docNodeContainer: DocNodeContainer, token: ExcerptToken): void {
  const configuration: TSDocConfiguration = this._tsdocConfiguration;

  // Markdown doesn't provide a standardized syntax for hyperlinks inside code spans, so we will render
  // the type expression as DocPlainText.  Instead of creating multiple DocParagraphs, we can simply
  // discard any newlines and let the renderer do normal word-wrapping.
  const unwrappedTokenText: string = token.text.replace(/[\r\n]+/g, ' ');

  // If it's hyperlinkable, then append a DocLinkTag
  if (token.kind === ExcerptTokenKind.Reference && token.canonicalReference) {
    const apiItemResult: IResolveDeclarationReferenceResult = this._apiModel.resolveDeclarationReference(
      token.canonicalReference,
      undefined
    );

    if (apiItemResult.resolvedApiItem) {
      docNodeContainer.appendNode(
        new DocLinkTag({
          configuration,
          tagName: '@link',
          linkText: unwrappedTokenText,
          urlDestination: this._getLinkFilenameForApiItem(apiItemResult.resolvedApiItem)
        })
      );
      return;
    }
  }

  // Otherwise append non-hyperlinked text
  docNodeContainer.appendNode(new DocPlainText({ configuration, text: unwrappedTokenText }));
}

public static columnFromVisibleColumn(lineContent: string, visibleColumn: number, tabSize: number): number {
	if (visibleColumn <= 0) {
		return 1;
	}

	const lineContentLength = lineContent.length;
	const iterator = new strings.GraphemeIterator(lineContent);

	let beforeVisibleColumn = 0;
	let beforeColumn = 1;
	while (!iterator.eol()) {
		const codePoint = strings.getNextCodePoint(lineContent, lineContentLength, iterator.offset);
		iterator.nextGraphemeLength();

		const afterVisibleColumn = this._nextVisibleColumn(codePoint, beforeVisibleColumn, tabSize);
		const afterColumn = iterator.offset + 1;

		if (afterVisibleColumn >= visibleColumn) {
			const beforeDelta = visibleColumn - beforeVisibleColumn;
			const afterDelta = afterVisibleColumn - visibleColumn;
			if (afterDelta < beforeDelta) {
				return afterColumn;
			} else {
				return beforeColumn;
			}
		}

		beforeVisibleColumn = afterVisibleColumn;
		beforeColumn = afterColumn;
	}

	// walked the entire string
	return lineContentLength + 1;
}

public async stop(): Promise<void> {
  if (!this.child) {
    return
  }

  const result = new Promise<void>((resolve) => {
    // Terminate the child process after a timeout if it's still running. On
    // Unix, this will send a SIGTERM signal to the process, which the schema
    // engine will handle and initiate a graceful shutdown. Since it has its
    // own timeout mechanism, we shouldn't wait before sending the signal,
    // otherwise these timeouts will add up. On Windows, there are no signals
    // and the kill method will terminate the process immediately, similar to
    // SIGKILL on Unix, so we should wait to give the schema engine a chance
    // to gracefully shut down in response to EOF in stdin.
    const timer = setTimeout(
      () => {
        this.child?.kill()
        resolve()
      },
      process.platform === 'win32' ? 4000 : 0,
    ).unref()

    this.child!.on('exit', () => {
      clearTimeout(timer)
      resolve()
    })
  })

  // Close stdin to tell the schema engine to stop the RPC server and exit.
  this.child.stdin?.end()

  this.isRunning = false

  return result
}

export function isValidHTMLNesting(parent: string, child: string): boolean {
  // if the parent is a template, it can have any child
  if (parent === 'template') {
    return true
  }

  // if we know the list of children that are the only valid children for the given parent
  if (parent in onlyValidChildren) {
    return onlyValidChildren[parent].has(child)
  }

  // if we know the list of parents that are the only valid parents for the given child
  if (child in onlyValidParents) {
    return onlyValidParents[child].has(parent)
  }

  // if we know the list of children that are NOT valid for the given parent
  if (parent in knownInvalidChildren) {
    // check if the child is in the list of invalid children
    // if so, return false
    if (knownInvalidChildren[parent].has(child)) return false
  }

  // if we know the list of parents that are NOT valid for the given child
  if (child in knownInvalidParents) {
    // check if the parent is in the list of invalid parents
    // if so, return false
    if (knownInvalidParents[child].has(parent)) return false
  }

  return true
}

function validateDependentOptions(options: PrismaClientOptions) {
  const adapterProvided = options.adapter !== undefined
  const accelerateUrlProvided = options.accelerateUrl !== undefined

  if (adapterProvided && accelerateUrlProvided) {
    throw new PrismaClientConstructorValidationError(
      `The "adapter" and "accelerateUrl" options are mutually exclusive. Please provide only one of them.`,
    )
  }

  if (!adapterProvided && !accelerateUrlProvided) {
    throw new PrismaClientConstructorValidationError(
      `Using engine type "client" requires either "adapter" or "accelerateUrl" to be provided to PrismaClient constructor.`,
    )
  }
}

export function validatePrismaClientOptions(options: PrismaClientOptions, config: ClientConfig) {
  for (const [key, value] of Object.entries(options)) {
    if (!knownProperties.includes(key)) {
      const didYouMean = getDidYouMean(key, knownProperties)
      throw new PrismaClientConstructorValidationError(
        `Unknown property ${key} provided to PrismaClient constructor.${didYouMean}`,
      )
    }
    validators[key](value, config)
  }

  validateDependentOptions(options)
}

accept<R>(visitor: DynamicValueVisitor<R>): R {
  switch (this.code) {
    case DynamicValueReason.DYNAMIC_INPUT:
      return visitor.visitDynamicInput(this as unknown as DynamicValue<DynamicValue>);
    case DynamicValueReason.DYNAMIC_STRING:
      return visitor.visitDynamicString(this);
    case DynamicValueReason.EXTERNAL_REFERENCE:
      return visitor.visitExternalReference(
        this as unknown as DynamicValue<Reference<ts.Declaration>>,
      );
    case DynamicValueReason.UNSUPPORTED_SYNTAX:
      return visitor.visitUnsupportedSyntax(this);
    case DynamicValueReason.UNKNOWN_IDENTIFIER:
      return visitor.visitUnknownIdentifier(this);
    case DynamicValueReason.INVALID_EXPRESSION_TYPE:
      return visitor.visitInvalidExpressionType(this);
    case DynamicValueReason.COMPLEX_FUNCTION_CALL:
      return visitor.visitComplexFunctionCall(
        this as unknown as DynamicValue<FunctionDefinition>,
      );
    case DynamicValueReason.DYNAMIC_TYPE:
      return visitor.visitDynamicType(this);
    case DynamicValueReason.SYNTHETIC_INPUT:
      return visitor.visitSyntheticInput(
        this as unknown as DynamicValue<SyntheticValue<unknown>>,
      );
    case DynamicValueReason.UNKNOWN:
      return visitor.visitUnknown(this);
  }
}

getOriginalLocation(
  line: number,
  column: number,
): {file: AbsoluteFsPath; line: number; column: number} | null {
  if (this.flattenedMappings.length === 0) {
    return null;
  }

  let position: number;
  if (line < this.startOfLinePositions.length) {
    position = this.startOfLinePositions[line] + column;
  } else {
    // The line is off the end of the file, so just assume we are at the end of the file.
    position = this.contents.length;
  }

  const locationSegment: SegmentMarker = {line, column, position, next: undefined};

  let mappingIndex = findLastMappingIndexBefore(
    this.flattenedMappings,
    locationSegment,
    false,
    0,
  );
  if (mappingIndex < 0) {
    mappingIndex = 0;
  }
  const {originalSegment, originalSource, generatedSegment} =
    this.flattenedMappings[mappingIndex];
  const offset = locationSegment.position - generatedSegment.position;
  const offsetOriginalSegment = offsetSegment(
    originalSource.startOfLinePositions,
    originalSegment,
    offset,
  );

  return {
    file: originalSource.sourcePath,
    line: offsetOriginalSegment.line,
    column: offsetOriginalSegment.column,
  };
}

export const getExpressionStringAtPos = (
  node: Node,
  pos: number,
  options?: PeekOverlayExpressionIdentifierOptions,
  replaceThisExpression = true,
): string | undefined => {
  if (!isPositionWithinNode(node, pos)) return;

  if (isMemberExpressionNode(node)) {
    return getExpressionAtPosFromMemberExpression(
      node,
      pos,
      options,
      replaceThisExpression,
    );
  } else if (isExpressionStatementNode(node)) {
    return getExpressionAtPosFromExpressionStatement(node, pos, options);
  } else if (isCallExpressionNode(node)) {
    return getExpressionAtPosFromCallExpression(node, pos, options);
  } else if (isBinaryExpressionNode(node)) {
    return getExpressionAtPosFromBinaryExpression(node, pos, options);
  } else if (isAwaitExpressionNode(node)) {
    return getExpressionStringAtPos(node.argument, pos, options);
  } else if (isConditionalExpressionNode(node)) {
    return getExpressionAtPosFromConditionalExpression(node, pos, options);
  } else if (isIdentifierNode(node)) {
    return removeSemiColon(escodegen.generate(node));
  }
};

export function* updateSectionWithDefaultSpaceDistribution(
  allWidgets: CanvasWidgetsReduxState,
  sectionWidget: FlattenedWidgetProps,
) {
  // Extracting necessary information from the section widget
  const sectionWidgetId = sectionWidget.widgetId;
  const zoneOrder: string[] = sectionWidget.layout[0].layout.map(
    (each: WidgetLayoutProps) => each.widgetId,
  );

  // Calculating the default space distribution for the zones within the section
  const defaultSpaceDistributed = getDefaultSpaceDistributed(zoneOrder);
  const updatedWidgets = { ...allWidgets };

  // Removing previous space distribution and updating widgets
  zoneOrder.forEach((eachChild: string) => {
    updatedWidgets[eachChild] = {
      ...updatedWidgets[eachChild],
      flexGrow: defaultSpaceDistributed[eachChild],
    };
    updatedWidgets[sectionWidgetId] = {
      ...updatedWidgets[sectionWidgetId],
      spaceDistributed: {
        ...updatedWidgets[sectionWidgetId].spaceDistributed,
        [eachChild]: defaultSpaceDistributed[eachChild],
      },
    };
  });

  // Updating the section widget with the new default space distribution
  return {
    ...updatedWidgets,
    [sectionWidgetId]: {
      ...updatedWidgets[sectionWidgetId],
      spaceDistributed: defaultSpaceDistributed,
    },
  };
}

export function* addNewZonesToSection(
  sectionWidgetId: string,
  numberOfZonesToCreate: number,
) {
  const allWidgets: CanvasWidgetsReduxState = yield select(getWidgets);
  let updatedWidgets = { ...allWidgets };
  let count = 0;
  const createdZoneIds: string[] = [];

  // Create and add the specified number of zones to the Section Widget
  do {
    const sectionWidget: FlattenedWidgetProps = updatedWidgets[sectionWidgetId];
    // TODO: Fix this the next time the file is edited
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const newWidget: any = {
      newWidgetId: generateReactKey(),
      parentId: sectionWidget.widgetId,
      type: anvilWidgets.ZONE_WIDGET,
    };
    const highlight = getSectionLastColumnHighlight(sectionWidget);

    updatedWidgets = yield call(
      getUpdatedListOfWidgetsAfterAddingNewWidget,
      highlight,
      newWidget,
      false,
      true,
    );
    createdZoneIds.push(newWidget.newWidgetId);
    count += 1;
  } while (count < numberOfZonesToCreate);

  return { updatedWidgets, createdZoneIds };
}

public bind(scope: IConstruct, logType: string, sourceResourceArn: string): ILogsDeliveryConfig {
  const container = new Construct(scope, deliveryId('S3', logType, scope, this.bucket));

  const deliverySource = getOrCreateDeliverySource(logType, scope, sourceResourceArn);
  const deliverySourceRef = deliverySource.deliverySourceRef;

  const deliveryDestination = new S3DeliveryDestination(container, makeDestId(logType), {
    bucket: this.bucket,
    permissionsVersion: this.permissions,
    encryptionKey: this.kmsKey,
    outputFormat: this.outputFormat,
  });

  const recordFields = computeRecordFields(this.providedFields, this.mandatoryFields);

  const delivery = new logs.CfnDelivery(container, 'Delivery', {
    deliveryDestinationArn: deliveryDestination.attrArn,
    deliverySourceName: deliverySourceRef.deliverySourceName,
    recordFields,
  });

  delivery.node.addDependency(deliverySource);
  delivery.node.addDependency(deliveryDestination);

  return {
    deliverySource,
    deliveryDestination,
    delivery,
  };
}

export default async function pre(
  rootDir: string,
  options: { command: "enter"; tag: string } | { command: "exit"; tag?: string }
) {
  if (options.command === "enter") {
    try {
      await enterPre(rootDir, options.tag);
      logger.success(`Entered pre mode with tag ${pc.cyan(options.tag)}`);
      logger.info(
        "Run `changeset version` to version packages with prerelease versions"
      );
    } catch (err) {
      if (err instanceof PreEnterButInPreModeError) {
        logger.error("`changeset pre enter` cannot be run when in pre mode");
        logger.info(
          "If you're trying to exit pre mode, run `changeset pre exit`"
        );
        throw new ExitError(1);
      }
      throw err;
    }
  } else {
    try {
      await exitPre(rootDir);
      logger.success(`Exited pre mode`);
      logger.info(
        "Run `changeset version` to version packages with normal versions"
      );
    } catch (err) {
      if (err instanceof PreExitButNotInPreModeError) {
        logger.error("`changeset pre exit` can only be run when in pre mode");
        logger.info(
          "If you're trying to enter pre mode, run `changeset pre enter`"
        );
        throw new ExitError(1);
      }
      throw err;
    }
  }
}

function processFieldAliases(
  fieldAlias: Record<string, any>,
  baseEntity: string,
  entitiesMap: Record<string, any>,
  entityMap: Map<string, EntityMapping>
): void {
  for (const [aliasName, aliasConfig] of Object.entries(fieldAlias)) {
    const aliasPath = isString(aliasConfig) ? aliasConfig : aliasConfig.path

    if (!aliasPath) {
      continue
    }

    // Build the complete path from base entity through alias path
    const pathSegments = aliasPath.split(".")
    let currentEntity = baseEntity
    let finalEntity = baseEntity
    let isValidPath = true

    // Traverse the path to find the final entity
    for (const segment of pathSegments) {
      const entityMapping = findFieldInEntity(
        currentEntity,
        segment,
        entitiesMap
      )

      if (!entityMapping) {
        isValidPath = false
        break
      }

      currentEntity = entityMapping.targetEntity
      finalEntity = entityMapping.targetEntity
    }

    if (isValidPath) {
      const fullPath = `${baseEntity}.${aliasName}`

      entityMap.set(fullPath, {
        entityName: aliasName,
        targetEntity: finalEntity,
        path: pathSegments,
      })
    }
  }
}

private _cloneMultipartModuleAliasDeclaration(
    node: ImportFromNode,
    declaration: AliasDeclaration
): AliasDeclaration {
    const clonedLoaderActions = this._cloneModuleLoaderActions(declaration);
    const clonedDeclaration: AliasDeclaration = {
        type: DeclarationType.Alias,
        node,
        uri: clonedLoaderActions.uri,
        loadSymbolsFromPath: clonedLoaderActions.loadSymbolsFromPath,
        range: getEmptyRange(),
        usesLocalName: false,
        moduleName: declaration.moduleName,
        firstNamePart: declaration.firstNamePart,
        isInExceptSuite: this._isInExceptSuite,
        implicitImports: clonedLoaderActions.implicitImports,
    };

    if (clonedLoaderActions.isUnresolved) {
        clonedDeclaration.isUnresolved = true;
    }

    if (declaration.isNativeLib) {
        clonedDeclaration.isNativeLib = true;
    }

    return clonedDeclaration;
}

export function getEvaluationNodeForAssignmentExpression(
    node: AssignmentExpressionNode
): LambdaNode | FunctionNode | ModuleNode | ClassNode | undefined {
    // PEP 572 indicates that the evaluation node for an assignment expression
    // target within a list comprehension is contained within a lambda,
    // function or module, but not a class.
    let sawComprehension = false;
    let curNode: ParseNode | undefined = getEvaluationScopeNode(node).node;

    while (curNode !== undefined) {
        switch (curNode.nodeType) {
            case ParseNodeType.Function:
            case ParseNodeType.Lambda:
            case ParseNodeType.Module:
                return curNode;

            case ParseNodeType.Class:
                return sawComprehension ? undefined : curNode;

            case ParseNodeType.Comprehension:
                sawComprehension = true;
                curNode = getEvaluationScopeNode(curNode.parent!).node;
                break;

            default:
                return undefined;
        }
    }

    return undefined;
}

private _getMembersAndWriteIncompleteWarning(
  apiClassOrInterface: ApiClass | ApiInterface,
  output: DocSection
): readonly ApiItem[] {
  const configuration: TSDocConfiguration = this._tsdocConfiguration;
  const showInheritedMembers: boolean = !!this._documenterConfig?.configFile.showInheritedMembers;
  if (!showInheritedMembers) {
    return apiClassOrInterface.members;
  }

  const result: IFindApiItemsResult = apiClassOrInterface.findMembersWithInheritance();

  // If the result is potentially incomplete, write a short warning communicating this.
  if (result.maybeIncompleteResult) {
    output.appendNode(
      new DocParagraph({ configuration }, [
        new DocEmphasisSpan({ configuration, italic: true }, [
          new DocPlainText({
            configuration,
            text: '(Some inherited members may not be shown because they are not represented in the documentation.)'
          })
        ])
      ])
    );
  }

  // Log the messages for diagnostic purposes.
  for (const message of result.messages) {
    console.log(`Diagnostic message for findMembersWithInheritance: ${message.text}`);
  }

  return result.items;
}

function handleDtsMayChangeOfAffectedFile(
    state: BuilderProgramStateWithDefinedProgram,
    affectedFile: SourceFile,
    cancellationToken: CancellationToken | undefined,
    host: BuilderProgramHost,
) {
    removeSemanticDiagnosticsOf(state, affectedFile.resolvedPath);

    // If affected files is everything except default library, then nothing more to do
    if (state.allFilesExcludingDefaultLibraryFile === state.affectedFiles) {
        removeDiagnosticsOfLibraryFiles(state);
        // When a change affects the global scope, all files are considered to be affected without updating their signature
        // That means when affected file is handled, its signature can be out of date
        // To avoid this, ensure that we update the signature for any affected file in this scenario.
        BuilderState.updateShapeSignature(
            state,
            state.program,
            affectedFile,
            cancellationToken,
            host,
        );
        return;
    }
    if (state.compilerOptions.assumeChangesOnlyAffectDirectDependencies) return;
    handleDtsMayChangeOfReferencingExportOfAffectedFile(
        state,
        affectedFile,
        cancellationToken,
        host,
    );
}

private elideSuffix(
	suffixBlock: WeightedBlock,
	suffixTokenLimit: number,
	prefixTokenLimit: number,
	maxPrefixTokens: number,
	tokenizer: Tokenizer
) {
	const suffix = suffixBlock.value;
	if (suffix.length === 0 || suffixTokenLimit <= 0) {
		const elidedSuffix: ElidedBlock = {
			...suffixBlock,
			tokens: 0,
			elidedValue: '',
			elidedTokens: 0,
		};
		return {
			elidedSuffix,
			adjustedPrefixTokenLimit: prefixTokenLimit + Math.max(0, suffixTokenLimit),
		};
	}

	// Check the maximum (approximate) length of the prefix.
	// If everything fits, we give the remaining budget to the suffix instead.
	if (maxPrefixTokens < prefixTokenLimit) {
		suffixTokenLimit = suffixTokenLimit + (prefixTokenLimit - maxPrefixTokens);
		prefixTokenLimit = maxPrefixTokens;
	}

	const shortenedSuffix = tokenizer.takeFirstTokens(suffix, suffixTokenLimit);
	const elidedSuffix: ElidedBlock = {
		...suffixBlock,
		// Update the original value and tokens
		value: suffix,
		tokens: tokenizer.tokenLength(suffix),
		elidedValue: shortenedSuffix.text,
		elidedTokens: shortenedSuffix.tokens.length,
	};

	return {
		elidedSuffix,
		adjustedPrefixTokenLimit: prefixTokenLimit + Math.max(0, suffixTokenLimit - shortenedSuffix.tokens.length),
	};
}

private emitMoveEvent(
  element: TargetElement,
  phase: GesturePhase,
  pointers: PointerData[],
  event: PointerEvent,
): void {
  const currentPosition = this.state.lastPosition || calculateCentroid(pointers);

  // Get list of active gestures
  const activeGestures = this.gesturesRegistry.getActiveGestures(element);

  // Create custom event data
  const customEventData: MoveGestureEventData = {
    gestureName: this.name,
    centroid: currentPosition,
    target: event.target,
    srcEvent: event,
    phase,
    pointers,
    timeStamp: event.timeStamp,
    activeGestures,
    customData: this.customData,
  };

  // Event names to trigger
  const eventName = createEventName(this.name, phase);

  // Dispatch custom events on the element
  const domEvent = new CustomEvent(eventName, {
    bubbles: true,
    cancelable: true,
    composed: true,
    detail: customEventData,
  });

  element.dispatchEvent(domEvent);
}

export function projectRRuleToTimezone(
  adapter: Adapter,
  rrule: SchedulerProcessedEventRecurrenceRule,
  targetTimezone: TemporalTimezone,
  seriesStartDataTimezone: TemporalSupportedObject,
): SchedulerProcessedEventRecurrenceRule {
  let nextRule = rrule;

  if (rrule.until) {
    nextRule = {
      ...nextRule,
      until: adapter.setTimezone(rrule.until, targetTimezone),
    };
  }

  if (rrule.byDay?.length) {
    if (rrule.freq === 'WEEKLY') {
      nextRule = {
        ...nextRule,
        byDay: projectWeeklyByDay(adapter, rrule.byDay, seriesStartDataTimezone, targetTimezone),
      };
    }

    // Monthly BYDAY with ordinals (e.g. 1MO, -1FR) is intentionally NOT projected.
    // Ordinals represent a calendar position in the event timezone and do not map
    // to a stable or meaningful rule in the display timezone.
    // Keeping the original rule avoids misleading UI representations.
  }

  return nextRule;
}

export function servePostTargetTransformer(migrationLogs: AggregatedLog) {
  return (
    target: TargetConfiguration,
    tree: Tree,
    projectDetails: { projectName: string; root: string },
    inferredTargetConfiguration: TargetConfiguration
  ) => {
    if (target.options) {
      handlePropertiesFromTargetOptions(
        tree,
        target.options,
        projectDetails.projectName,
        projectDetails.root
      );
    }

    if (target.configurations) {
      for (const configurationName in target.configurations) {
        const configuration = target.configurations[configurationName];

        handlePropertiesFromTargetOptions(
          tree,
          configuration,
          projectDetails.projectName,
          projectDetails.root
        );
      }

      if (Object.keys(target.configurations).length === 0) {
        if ('defaultConfiguration' in target) {
          delete target.defaultConfiguration;
        }
        delete target.configurations;
      }

      if (
        'defaultConfiguration' in target &&
        !target.configurations[target.defaultConfiguration]
      ) {
        delete target.defaultConfiguration;
      }
    }

    return target;
  };
}

export function previewPostTargetTransformer(migrationLogs: AggregatedLog) {
  return (
    target: TargetConfiguration,
    tree: Tree,
    projectDetails: { projectName: string; root: string },
    inferredTargetConfiguration: TargetConfiguration
  ) => {
    const viteConfigPath = getViteConfigPath(tree, projectDetails.root);

    if (target.options) {
      removePropertiesFromTargetOptions(
        target.options,
        projectDetails.projectName,
        migrationLogs
      );
    }

    if (target.configurations) {
      for (const configurationName in target.configurations) {
        const configuration = target.configurations[configurationName];
        removePropertiesFromTargetOptions(
          configuration,
          projectDetails.projectName,
          migrationLogs
        );
      }

      if (Object.keys(target.configurations).length === 0) {
        if ('defaultConfiguration' in target) {
          delete target.defaultConfiguration;
        }
        delete target.configurations;
      }

      if (
        'defaultConfiguration' in target &&
        !target.configurations[target.defaultConfiguration]
      ) {
        delete target.defaultConfiguration;
      }
    }

    return target;
  };
}

export function validateStructure(sourceFile: SourceFile): WriteResult {
  debug('[AST] Validating payload config structure')

  const detection = detectPayloadConfigStructure(sourceFile)

  if (!detection.success) {
    debug('[AST] ✗ Validation failed: detection unsuccessful')
    return {
      error: detection.error,
      success: false,
    }
  }

  const { structures } = detection

  // Validate db property exists
  if (!structures?.dbProperty) {
    debug('[AST] ✗ Validation failed: db property missing')
    return {
      error: formatError({
        actual: 'No db property found',
        context: 'database configuration',
        expected: 'buildConfig must have a db property',
        technicalDetails: 'PropertyAssignment with name "db" not found in buildConfig object',
      }),
      success: false,
    }
  }

  debug('[AST] ✓ Validation passed')
  return { success: true }
}

async function buildEmail(emailConfig?: NodemailerAdapterArgs): Promise<{
  defaultFromAddress: string
  defaultFromName: string
  transport: Transporter
}> {
  if (!emailConfig) {
    const transport = await createMockAccount(emailConfig)
    if (!transport) {
      throw new InvalidConfiguration('Unable to create Nodemailer test account.')
    }

    return {
      defaultFromAddress: 'info@payloadcms.com',
      defaultFromName: 'Payload',
      transport,
    }
  }

  // Create or extract transport
  let transport: Transporter
  if ('transport' in emailConfig && emailConfig.transport) {
    ;({ transport } = emailConfig)
  } else if ('transportOptions' in emailConfig && emailConfig.transportOptions) {
    transport = nodemailer.createTransport(emailConfig.transportOptions)
  } else {
    transport = await createMockAccount(emailConfig)
  }

  if (!emailConfig.skipVerify) {
    await verifyTransport(transport)
  }

  return {
    defaultFromAddress: emailConfig.defaultFromAddress,
    defaultFromName: emailConfig.defaultFromName,
    transport,
  }
}

export function buildAuditPathIndex (
  lockfile: LockfileObject,
  vulnerableNames: Set<string>,
  opts: AuditIndexOptions
): AuditPathIndex {
  // Null-prototype record keyed by package name to avoid prototype pollution
  // from registry-supplied or lockfile-supplied names.
  const paths: AuditPathIndex = Object.create(null)
  const depTypes = opts.depTypes ?? detectDepTypes(lockfile)
  const optionalOnly = opts.optionalOnly ?? collectOptionalOnlyDepPaths(lockfile, opts.include)

  walkForPaths({
    lockfile,
    vulnerableNames,
    paths,
    depTypes,
    optionalOnly,
    include: opts.include,
    importerSegmentOf: (importerId) => importerId.replace(/\//g, '__'),
  })

  if (opts.envLockfile) {
    const envLockfileObject = envLockfileToLockfileObject(opts.envLockfile)
    walkForPaths({
      lockfile: envLockfileObject,
      vulnerableNames,
      paths,
      depTypes: detectDepTypes(envLockfileObject),
      optionalOnly: collectOptionalOnlyDepPaths(envLockfileObject, opts.include),
      include: opts.include,
      importerSegmentOf: (importerId) => importerId,
    })
  }

  return paths
}

function getDependenciesFromLicenseNode (
  licenseNode: LicenseNode
): LicensePackage[] {
  if (!licenseNode.dependencies) {
    return []
  }

  let dependencies: LicensePackage[] = []
  for (const dependencyName in licenseNode.dependencies) {
    const dependencyNode = licenseNode.dependencies[dependencyName]
    const dependenciesOfNode = getDependenciesFromLicenseNode(dependencyNode)

    dependencies = [
      ...dependencies,
      ...dependenciesOfNode,
      {
        belongsTo: dependencyNode.dev ? 'devDependencies' : 'dependencies',
        version: dependencyNode.version as string,
        name: dependencyName,
        license: dependencyNode.license as string,
        licenseContents: dependencyNode.licenseContents,
        author: dependencyNode.author as string,
        homepage: dependencyNode.homepage as string,
        description: dependencyNode.description,
        repository: dependencyNode.repository as string,
        path: dependencyNode.dir,
      },
    ]
  }

  return dependencies
}

private async executeLinkFlow(
  apiKey: string | undefined,
  databaseId: string | undefined,
  baseDir: string,
): Promise<LinkResult> {
  const client = await resolveApiClient(apiKey)

  let workspaceId: string | null = null
  let projectId: string | null = null

  if (!databaseId) {
    const resolved = await resolveDatabase(client)
    databaseId = resolved.databaseId
    workspaceId = resolved.workspaceId
    projectId = resolved.projectId
  } else {
    workspaceId = apiKey ? extractWorkspaceIdFromToken(apiKey) : null
    projectId = await resolveProjectForDatabase(client, databaseId)
  }

  const connection = await createDevConnection(client, databaseId)
  const localFilesResult = writeLocalFiles(baseDir, connection)
  const hasModels = getModelNames(baseDir).length > 0
  const environmentId = databaseId.replace(/^db_/, '')

  return {
    workspaceId: workspaceId ?? 'unknown',
    projectId: projectId ?? 'unknown',
    environmentId,
    databaseId,
    connectionString: connection.connectionString,
    localFilesResult,
    hasModels,
  }
}

export function getAndIncludeFactoryVariable(
	factory: string,
	preserve: boolean,
	importSource: string | null,
	node: JSXElementBase | JSXOpeningElement | JSXOpeningFragment,
	context: InclusionContext
): Variable {
	const [baseName, nestedName] = factory.split('.');
	let factoryVariable: Variable;
	if (importSource) {
		factoryVariable = node.scope.context.getImportedJsxFactoryVariable(
			nestedName ? 'default' : baseName,
			node.start,
			importSource
		);
		if (preserve) {
			// This pretends we are accessing an included global variable of the same name
			const globalVariable = node.scope.findGlobal(baseName);
			globalVariable.includePath(UNKNOWN_PATH, context);
			// This excludes this variable from renaming
			factoryVariable.globalName = baseName;
		}
	} else {
		factoryVariable = node.scope.findGlobal(baseName);
	}
	node.scope.context.includeVariableInModule(factoryVariable, UNKNOWN_PATH, context);
	if (factoryVariable instanceof LocalVariable) {
		factoryVariable.consolidateInitializers();
		factoryVariable.addUsedPlace(node);
		node.scope.context.requestTreeshakingPass();
	}
	return factoryVariable;
}

function getDynamicallyDependentEntriesByDynamicEntry(
	dependentEntriesByModule: ReadonlyMap<Module, ReadonlySet<number>>,
	dynamicEntries: ReadonlySet<number>,
	allEntries: readonly Module[],
	getDynamicImporters: (entry: Module) => Iterable<Module>
): Map<number, Set<number>> {
	const dynamicallyDependentEntriesByDynamicEntry = new Map<number, Set<number>>();
	for (const dynamicEntryIndex of dynamicEntries) {
		const dynamicallyDependentEntries = getOrCreate(
			dynamicallyDependentEntriesByDynamicEntry,
			dynamicEntryIndex,
			getNewSet<number>
		);
		const dynamicEntry = allEntries[dynamicEntryIndex];
		for (const importer of concatLazy([
			getDynamicImporters(dynamicEntry),
			dynamicEntry.implicitlyLoadedAfter
		])) {
			const importerEntries = dependentEntriesByModule.get(importer);
			if (!importerEntries) {
				continue;
			}
			for (const entry of importerEntries) {
				dynamicallyDependentEntries.add(entry);
			}
		}
	}
	return dynamicallyDependentEntriesByDynamicEntry;
}
